_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUv+uTexSize.zw*.5;
//vUv = (vUv-.5)*q32/4 + 0.5;
vUv += q31 * .1*(texture(sampler_pw_noise_lq,(vUv-.5)*q32+rand_frame.xy*q31)-.5);
uv1 = vUv-vec2(.5,.5+up);
vec3 Get1 = mix(GetPixel(vUv), GetBlur1(vUv),.2);

bdist = 1-Get1.b;;
float struc0 = Get1.r;

cloud = 0;
float z0 = clamp(.25/(uv1.y-.3),-.7,.0) ;
vec2 trel =  .015*uTime * vec2(q20,q21);

for (int n = 1; n <= 4; n++) {
  z = z0 + cloud*.015;
  uv2 = vec2 (uv1.x*z,z*1)*1 - trel;
  cloud = lum(texture(sampler_noise_hq,uv2 +.015*noise4(uv2*3+2*trel)));
}
float flash0 = sat(audioLowSmooth-1);
vec3 flash = flash0/length(vUv.xy-cloud*.2-fpos)*(1-cloud)*vec3(0,0.3,.6);

vec3 sky = (1-cloud)*skycol+ flash;

uv3 = vUv*vec2(6,3);
sky *= sat(16*GetBlur1(fract(uv3+floor(uv3.x)*.3)).r -64*(uv1.y+.1));//background
sky *= sat(bdist*16-15) ;

struc = mix(gvol*lavcol(struc0),struc0,bdist)*(1.2-bdist) * sat(1.25-length(vUv-lpos));

//vUv = (vUv-.5)*1+.5;
vec2 shlen = (2-fpos);
vec2 uv3 =  fract(vUv - shlen*.01*(1-0*Get1.b) );
float fac = 1.2-sat(4*((GetBlur1(uv3).b)-.1 - Get1.b ));

float relief = 1+0*(Get1 - GetBlur1(vUv+.001*rand_frame.xy)).r;

struc  += 8*struc0*struc0 * relief*sat(2*audioHighSmooth-3) * mix(bdist,1-bdist,rand_frame.x>.5)*fac*skycol;

ret = sky + struc;

//ret = struc0 * fac;

  fragColor = ret;
}
